    let minDiff = Infinity;

    // 4. Iterate through all pairs (i, j) where i is an index of 1 and j is an index of 2
    for (const i of onesIndices) {
        for (const j of twosIndices) {
            const diff = Math.abs(i - j);
            if (diff < minDiff) {
